private EmbeddedAspireSkillsBundleMetadata? LoadMetadata()
    {
        using var stream = typeof(EmbeddedAspireSkillsBundleProvider).Assembly.GetManifestResourceStream(MetadataResourceName);
        if (stream is null)
        {
            _logger.LogDebug("Embedded Aspire skills metadata resource {ResourceName} was not found.", MetadataResourceName);
            return null;
        }

        try
        {
            var metadata = JsonSerializer.Deserialize(
                stream,
                AspireSkillsJsonSerializerContext.Default.EmbeddedAspireSkillsBundleMetadata);

            if (metadata is null)
            {
                _logger.LogDebug("Embedded Aspire skills metadata resource {ResourceName} was empty.", MetadataResourceName);
            }

            return metadata;
        }
        catch (JsonException ex)
        {
            _logger.LogWarning(ex, "Embedded Aspire skills metadata resource {ResourceName} could not be parsed.", MetadataResourceName);
            return null;
        }
    }

private static string? ExtractBundleJson(string attestationJson, out bool parseFailed)
    {
        var bundleJson = SigstoreNpmProvenanceChecker.ExtractSlsaBundleJson(attestationJson, out parseFailed);
        if (bundleJson is not null || parseFailed)
        {
            return bundleJson;
        }

        JsonNode? document;
        try
        {
            document = JsonNode.Parse(attestationJson);
        }
        catch (JsonException)
        {
            parseFailed = true;
            return null;
        }

        if (document?["attestations"] is not JsonArray attestations)
        {
            return null;
        }

        foreach (var attestation in attestations)
        {
            var bundleNode = attestation?["bundle"];
            if (bundleNode is null)
            {
                continue;
            }

            if (bundleNode is JsonValue bundleValue && bundleValue.TryGetValue<string>(out var bundleString))
            {
                return bundleString;
            }

            return bundleNode.ToJsonString();
        }

        return null;
    }

public async Task<ExecuteResourceCommandResponse> ExecuteResourceCommandAsync(
    string resourceName,
    string commandName,
    ExecuteResourceCommandOptions? options = null,
    CancellationToken cancellationToken = default)
{
    options ??= new ExecuteResourceCommandOptions();

    var rpc = EnsureConnected();

    _logger.LogDebug("Executing command '{CommandName}' on resource '{ResourceName}'", commandName, resourceName);

    var request = new ExecuteResourceCommandRequest
    {
        ResourceName = resourceName,
        CommandName = commandName,
        Arguments = options.Arguments,
        ValidateOnly = options.ValidateOnly,
        NonInteractive = options.NonInteractive,
        ReturnArgumentInputs = options.ReturnArgumentInputs
    };

    var response = await rpc.InvokeWithProfilingAsync<ExecuteResourceCommandResponse>(
        _profilingTelemetry,
        "auxiliary",
        "ExecuteResourceCommandAsync",
        [request],
        cancellationToken).ConfigureAwait(false);

    _logger.LogDebug("Command '{CommandName}' on resource '{ResourceName}' completed with success={Success} and message='{Message}'", commandName, resourceName, response.Success, response.Message);

    return response;
}

public async Task<WaitForResourceResponse> WaitForResourceAsync(
    string resourceName,
    string status,
    int timeoutSeconds,
    CancellationToken cancellationToken = default)
{
    if (!SupportsV2)
    {
        return new WaitForResourceResponse
        {
            Success = false,
            ErrorMessage = "Wait command is not supported by the AppHost version. Update the AppHost to use this command."
        };
    }

    var rpc = EnsureConnected();

    _logger.LogDebug("Waiting for resource '{ResourceName}' to reach status '{Status}' with timeout {Timeout}s", resourceName, status, timeoutSeconds);

    var request = new WaitForResourceRequest
    {
        ResourceName = resourceName,
        Status = status,
        TimeoutSeconds = timeoutSeconds
    };

    var response = await rpc.InvokeWithProfilingAsync<WaitForResourceResponse>(
        _profilingTelemetry,
        "auxiliary",
        "WaitForResourceAsync",
        [request],
        cancellationToken).ConfigureAwait(false);

    _logger.LogDebug("Wait for resource '{ResourceName}' completed: success={Success}, state={State}", resourceName, response.Success, response.State);

    return response;
}

private async Task ReconnectInternalAsync()
    {
        if (_socketPath is null)
        {
            throw new InvalidOperationException("Cannot reconnect: no previous connection.");
        }

        ResetForReconnection();

        // Wait for the new socket to appear (the new DistributedApplication needs to start)
        var startTime = DateTime.UtcNow;
        var maxWait = TimeSpan.FromSeconds(30);

        var retryCount = 0;
        while (!_cancellationToken.IsCancellationRequested)
        {
            try
            {
                await ConnectAsync(_socketPath, _autoReconnect, retryCount, _cancellationToken).ConfigureAwait(false);
                logger.LogInformation("Successfully reconnected to backchannel");
                return;
            }
            catch (SocketException) when (DateTime.UtcNow - startTime < maxWait)
            {
                retryCount++;
                // Socket not ready yet, wait and retry
                await Task.Delay(500, _cancellationToken).ConfigureAwait(false);
            }
            catch (SocketException)
            {
                // Timeout exceeded — fall through to warning
                break;
            }
        }

        logger.LogWarning("Timed out waiting for backchannel reconnection");
    }

internal static void TryCleanupStaleVersions(string versionsRoot, string activeVersionId)
    {
        if (!Directory.Exists(versionsRoot))
        {
            return;
        }

        foreach (var entry in Directory.EnumerateDirectories(versionsRoot))
        {
            var name = Path.GetFileName(entry);

            // Keep the active version.
            if (string.Equals(name, activeVersionId, StringComparison.Ordinal))
            {
                continue;
            }

            if (BundleVersionLease.HasActiveLease(entry))
            {
                continue;
            }

            try
            {
                Directory.Delete(entry, recursive: true);
            }
            catch (Exception ex) when (ex is IOException or UnauthorizedAccessException)
            {
                // If deletion fails after lease probing, leave the directory untouched.
                // A later setup/update can retry without invalidating a potential reader.
            }
        }
    }

