            {
                Field = field,
                Value = qualifier.Value,
                Condition = ToFilterCondition(qualifier.Operator, negated: true)
            });
        }
    }

protected override async Task<AuthenticateResult> HandleAuthenticateAsync()
    {
        var options = dashboardOptions.CurrentValue;

        foreach (var scheme in GetRelevantAuthenticationSchemes())
        {
            var result = await Context.AuthenticateAsync(scheme).ConfigureAwait(false);

            if (result.Failure is not null)
            {
                return result;
            }
        }

        var id = new ClaimsIdentity([new Claim(OtlpAuthorization.OtlpClaimName, bool.TrueString)]);

        return AuthenticateResult.Success(new AuthenticationTicket(new ClaimsPrincipal(id), Scheme.Name));

        IEnumerable<string> GetRelevantAuthenticationSchemes()
        {
            yield return ConnectionTypeAuthenticationDefaults.AuthenticationSchemeOtlp;

            if (options.Otlp.AuthMode is OtlpAuthMode.ApiKey)
            {
                yield return OtlpApiKeyAuthenticationDefaults.AuthenticationScheme;
            }
            else if (options.Otlp.AuthMode is OtlpAuthMode.ClientCertificate)
            {
                yield return CertificateAuthenticationDefaults.AuthenticationScheme;
            }
        }
    }

private static HashSet<SpanWaterfallViewModel> BuildContextVisibleSet(
    IReadOnlyList<SpanWaterfallViewModel> spanWaterfallViewModels,
    string filter,
    TelemetryFilter? typeFilter,
    IReadOnlyList<FieldTelemetryFilter> contextFilters,
    Func<OtlpResourceView, string> getResourceName,
    Dictionary<SpanWaterfallViewModel, SpanWaterfallViewModel> parentMap)
{
    var visibleViewModels = new HashSet<SpanWaterfallViewModel>();

    foreach (var viewModel in spanWaterfallViewModels)
    {
        if (visibleViewModels.Contains(viewModel))
        {
            continue;
        }

        // Only context filters participate in tree-aware expansion. Direct matches
        // keep their descendants visible and matching descendants keep their
        // ancestors visible, but the scan itself stays linear instead of recursively
        // walking each subtree from every flat-list row.
        if (viewModel.MatchesFilterDirect(filter, typeFilter, contextFilters, getResourceName))
        {
            AddContextMatch(viewModel, visibleViewModels, parentMap);
        }
    }

    return visibleViewModels;
}

private async Task InvokeToolCallbackAsync(string toolName, string message, CancellationToken cancellationToken)
    {
        _toolCallCounts.AddOrUpdate(toolName, 1, (_, count) => count + 1);
        UpdateTelemetryProperties();

        if (OnToolInvokedCallback is { } callback)
        {
            if (_currentAssistantResponse is not null)
            {
                lock (_lock)
                {
                    EnsureNoResponsePlaceholder();

                    // End tool call message with new lines so following content starts a new paragraph.
                    var resolvedMessage = message + Environment.NewLine + Environment.NewLine;

                    // Start tool call message with new lines so tool call message starts a new paragraph.
                    if (_responseState == ResponseState.ResponseText)
                    {
                        resolvedMessage = Environment.NewLine + Environment.NewLine + resolvedMessage;
                    }

                    UpdateAssistantResponseHtml(resolvedMessage, inCompleteDocument: false);
                    _responseState = ResponseState.ToolCall;
                }

                await callback(toolName, message, cancellationToken).ConfigureAwait(false);
            }
        }
    }
